    for (int i = 0; i < a_size; i++) {
        if (strcmp(a[i], b[i]) != 0) {
            return 0;
        }
    }
    return 1;
}

void free_groups(char** groups, int size) {
    for (int i = 0; i < size; i++) {
        free(groups[i]);
    }
    free(groups);
}

